{
  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "dataModel": {
    "enums": {
      "Mood": ["happy", "tired", "healthy", "indulgent", "rush"],
      "MealTime": ["breakfast", "lunch", "dinner", "lateNight"],
      "Taste": ["light", "heavy", "sweetSour", "spicy", "random"],
      "MealType": ["breakfast", "lunch", "dinner", "snack"]
    },
    "entities": {
      "Dish": {
        "fields": ["id", "name", "category", "ingredients[]", "mealTimes[]", "moods[]", "tastes[]", "cookMinutes", "tags[]"],
        "source": "built-in local DishLibrary (no network)"
      },
      "Ingredient": {
        "fields": ["id", "name"],
        "source": "user-added, persisted locally",
        "note": "name normalized to lowercase for matching"
      },
      "CheckinLog": {
        "fields": ["id", "date(yyyy-MM-dd)", "mealType", "dishName", "note?", "createdAtMs"],
        "source": "user-created, persisted locally"
      },
      "ShareCardData": {
        "fields": ["title", "dishName", "date", "tagline", "source(decision|checkin)"],
        "derivedFrom": "currentDecision or selected checkin log"
      },
      "RecommendResult": {
        "fields": ["dish", "matchCount", "matchScore", "matchKind(full|partial|mainOnly)"]
      }
    },
    "sharedState": {
      "currentDecision": "Dish | null — today's chosen dish, shared across home/mood/share via AppStorage key 'currentDecision'",
      "lastSpinAtMs": "number | 0"
    },
    "persistence": {
      "store": "@ohos.data.preferences",
      "keys": {
        "ingredients": "json array of Ingredient",
        "checkins": "json array of CheckinLog",
        "decisionHistory": "json array of {date, dishId, dishName}"
      },
      "firstLaunch": "no seeded ingredients/checkins; DishLibrary is the only built-in data"
    }
  },
  "services": {
    "StorageService": {
      "duty": "preferences load/put/flush for ingredients, checkins, decisionHistory; returns parsed arrays",
      "api": ["getIngredients()", "saveIngredients(list)", "getCheckins()", "saveCheckins(list)", "appendDecision(record)", "clearAll()"]
    },
    "RecommendService": {
      "duty": "all local recommendation/filter/spin logic, stateless over DishLibrary",
      "api": [
        "spinWheel(dishes?, count=8): {segments:Dish[], targetIndex:number, rotations:number, durationMs:number}",
        "recommendByIngredients(ingredients, dishes): RecommendResult[] sorted full>partial>mainOnly then matchCount desc",
        "filterDishes(mood, mealTime, taste, dishes): Dish[]"
      ]
    },
    "DishLibrary": {
      "duty": "static built-in dish catalog (~24 dishes) with ingredient/mealTime/mood/taste metadata",
      "note": "only built-in data; used as offline recommendation basis"
    }
  },
  "stateMachine": {
    "wheel": {
      "states": ["idle", "spinning", "settled"],
