// Types.ets
//
// Shared domain types for the "今天吃什么" decision app.
// Headless logic layer: enums + entity interfaces used by services and controllers.
// Kept free of ArkUI decorators so it can be unit-reasoned and statically checked.

// --- Enumerations (string unions as const objects for ArkTS compatibility) ---

export class Mood {
  static readonly HAPPY: string = 'happy';
  static readonly TIRED: string = 'tired';
  static readonly HEALTHY: string = 'healthy';
  static readonly INDULGENT: string = 'indulgent';
  static readonly RUSH: string = 'rush';

  static readonly ALL: string[] = [
    Mood.HAPPY, Mood.TIRED, Mood.HEALTHY, Mood.INDULGENT, Mood.RUSH,
  ];
}

export class MealTime {
  static readonly BREAKFAST: string = 'breakfast';
  static readonly LUNCH: string = 'lunch';
  static readonly DINNER: string = 'dinner';
  static readonly LATE_NIGHT: string = 'lateNight';

  static readonly ALL: string[] = [
    MealTime.BREAKFAST, MealTime.LUNCH, MealTime.DINNER, MealTime.LATE_NIGHT,
  ];
}

export class Taste {
  static readonly LIGHT: string = 'light';
  static readonly HEAVY: string = 'heavy';
  static readonly SWEET_SOUR: string = 'sweetSour';
  static readonly SPICY: string = 'spicy';
  static readonly RANDOM: string = 'random';

  static readonly ALL: string[] = [
    Taste.LIGHT, Taste.HEAVY, Taste.SWEET_SOUR, Taste.SPICY, Taste.RANDOM,
  ];
}

// MealType is the checkin record's meal category (breakfast/lunch/dinner/snack).
export class MealType {
  static readonly BREAKFAST: string = 'breakfast';
  static readonly LUNCH: string = 'lunch';
  static readonly DINNER: string = 'dinner';
  static readonly SNACK: string = 'snack';

  static readonly ALL: string[] = [
    MealType.BREAKFAST, MealType.LUNCH, MealType.DINNER, MealType.SNACK,
  ];
}

// --- Entities ---

export interface Dish {
  id: string;
  name: string;
  category: string;          // 家常菜 / 快手菜 / 早餐 / 汤面 ...
  ingredients: string[];     // normalized lowercase main ingredients
  mealTimes: string[];       // MealTime values
  moods: string[];           // Mood values
  tastes: string[];          // Taste values
  cookMinutes: number;
  tags: string[];
}

export interface Ingredient {
  id: string;
  name: string;              // display name as typed by user
}

export interface CheckinLog {
  id: string;
  date: string;              // yyyy-MM-dd (local)
  mealType: string;          // MealType value
  dishName: string;
  note: string;              // optional, may be ''
  createdAtMs: number;
}

export interface DecisionRecord {
  date: string;              // yyyy-MM-dd
  dishId: string;
  dishName: string;
}

export interface RecommendResult {
  dish: Dish;
  matchCount: number;
  matchScore: number;        // 0..100
  matchKind: string;         // 'full' | 'partial' | 'mainOnly'
}

export interface ShareCardData {
  title: string;
  dishName: string;
  date: string;
  tagline: string;
  source: string;            // 'decision' | 'checkin'
}

export interface SpinResult {
  segments: Dish[];
  targetIndex: number;
  rotations: number;
  durationMs: number;
}

// --- Helpers ---

export function normalizeIngredientName(raw: string): string {
  return raw.trim().toLowerCase();
}

export function todayDateString(): string {
  // Local date in yyyy-MM-dd. Date() with no args is allowed in app runtime;
  // this is not a workflow-script context.
  const d = new Date();
  const y = d.getFullYear();
  const m = (d.getMonth() + 1).toString().padStart(2, '0');
  const day = d.getDate().toString().padStart(2, '0');
  return `${y}-${m}-${day}`;
}

export function defaultMealTypeForNow(): string {
  const h = new Date().getHours();
  if (h < 10) return MealType.BREAKFAST;
  if (h < 14) return MealType.LUNCH;
  if (h < 18) return MealType.SNACK;
  return MealType.DINNER;
}

