        if (item && typeof item.id === 'string' && typeof item.name === 'string') {
          out.push({ id: item.id, name: item.name });
        }
      }
      return out;
    } catch (e) {
      return [];
    }
  }

  private static parseCheckins(raw: string): CheckinLog[] {
    if (!raw) return [];
    try {
      const arr: object[] = JSON.parse(raw) as object[];
      const out: CheckinLog[] = [];
      for (const o of arr) {
        const item = o as CheckinLog;
        if (item && typeof item.id === 'string' && typeof item.date === 'string'
          && typeof item.mealType === 'string' && typeof item.dishName === 'string') {
          out.push({
            id: item.id,
            date: item.date,
            mealType: item.mealType,
            dishName: item.dishName,
            note: typeof item.note === 'string' ? item.note : '',
            createdAtMs: typeof item.createdAtMs === 'number' ? item.createdAtMs : 0,
          });
        }
      }
      return out;
    } catch (e) {
