// WheelController.ets
//
// Owns the wheel state machine: idle -> spinning -> settled.
// Exposes spin() producing a SpinResult and, on settle, commits the result
// to DecisionStore + decision history.

import { RecommendService } from '../services/RecommendService';
import { StorageService } from '../services/StorageService';
import {
  Dish,
  SpinResult,
  todayDateString,
} from '../model/Types';
import { DecisionStore } from './DecisionStore';

export type WheelPhase = 'idle' | 'spinning' | 'settled';

export class WheelController {
  phase: WheelPhase = 'idle';
  segments: Dish[] = [];
  targetIndex: number = 0;
  resultDish: Dish | null = null;
  rotations: number = 5;
  durationMs: number = 3200;

  // Produces the next spin parameters and transitions to spinning.
  // The caller drives the animation; call settle() when durationMs elapses.
  spin(): SpinResult {
    const res: SpinResult = RecommendService.spin(8);
    this.segments = res.segments;
    this.targetIndex = res.targetIndex;
    this.rotations = res.rotations;
    this.durationMs = res.durationMs;
    this.phase = 'spinning';
    this.resultDish = null;
    return res;
  }

  // Commit the spin result. Called after the spin animation completes.
  async settle(): Promise<Dish | null> {
    if (this.segments.length === 0) {
      this.phase = 'idle';
      return null;
    }
    const idx = Math.min(this.targetIndex, this.segments.length - 1);
    const dish = this.segments[idx];
    this.resultDish = dish;
    this.phase = 'settled';
    DecisionStore.set(dish);
    await StorageService.appendDecision({
      date: todayDateString(),
      dishId: dish.id,
      dishName: dish.name,
    });
    return dish;
  }

  reset(): void {
    this.phase = 'idle';
    this.resultDish = null;
  }
}

