// IngredientsController.ets
//
// Manages the fridge ingredient list and ingredient-based recommendations.
// Persists changes through StorageService; recommendation results are in-memory.

import { RecommendService } from '../services/RecommendService';
import { StorageService } from '../services/StorageService';
import { Ingredient, normalizeIngredientName, RecommendResult } from '../model/Types';

let ingredientSeq = 0;

function nextIngredientId(): string {
  ingredientSeq += 1;
  return `ing-${Date.now()}-${ingredientSeq}`;
}

export class IngredientsController {
  items: Ingredient[] = [];
  newItemText: string = '';
  recommendResults: RecommendResult[] = [];

  async load(): Promise<Ingredient[]> {
    this.items = await StorageService.getIngredients();
    return this.items;
  }

  // Returns true if an item was added. Dedupes case-insensitively.
  async add(): Promise<boolean> {
    const name = this.newItemText.trim();
    if (name.length === 0) return false;
    const normalized = normalizeIngredientName(name);
    for (const it of this.items) {
      if (normalizeIngredientName(it.name) === normalized) {
        this.newItemText = '';
        return false;
      }
    }
    this.items.push({ id: nextIngredientId(), name });
    this.newItemText = '';
    await StorageService.saveIngredients(this.items);
    return true;
  }

  async remove(id: string): Promise<void> {
    this.items = this.items.filter((it) => it.id !== id);
    await StorageService.saveIngredients(this.items);
  }

  recommend(): RecommendResult[] {
    this.recommendResults = RecommendService.recommendByIngredients(this.items);
    return this.recommendResults;
  }
}

