//
// Mood / meal-time / taste filter state + filter() / useDish().
// useDish() promotes a filtered dish to the shared current decision.

import { RecommendService } from '../services/RecommendService';
import { Dish } from '../model/Types';
import { DecisionStore } from './DecisionStore';

export class MoodController {
  selectedMood: string = '';
  selectedMealTime: string = '';
  selectedTaste: string = '';
  filterResults: Dish[] = [];

  // Setters used by chip selectors.
  setMood(v: string): void { this.selectedMood = v; }
  setMealTime(v: string): void { this.selectedMealTime = v; }
  setTaste(v: string): void { this.selectedTaste = v; }

  filter(): Dish[] {
    this.filterResults = RecommendService.filterDishes(
      this.selectedMood, this.selectedMealTime, this.selectedTaste);
    return this.filterResults;
  }

  // Promote a chosen filtered dish to today's decision.
  useDish(dish: Dish): void {
    DecisionStore.set(dish);
  }

  hasAnySelection(): boolean {
    return this.selectedMood.length > 0
      || this.selectedMealTime.length > 0
      || (this.selectedTaste.length > 0 && this.selectedTaste !== 'random');
  }
}

