  async save(): Promise<CheckinLog | null> {
    if (!this.canSave()) return null;
    const log: CheckinLog = {
      id: nextCheckinId(),
      date: todayDateString(),
      mealType: this.newMealType,
      dishName: this.newDishName.trim(),
      note: this.newNote.trim(),
      createdAtMs: Date.now(),
    };
    this.logs.push(log);
    await StorageService.saveCheckins(this.logs);
    this.rebuildCalendar();
    this.formOpen = false;
    this.newDishName = '';
    this.newNote = '';
    return log;
  }

  async remove(id: string): Promise<void> {
    this.logs = this.logs.filter((l) => l.id !== id);
    await StorageService.saveCheckins(this.logs);
    this.rebuildCalendar();
  }

  logsForDate(date: string): CheckinLog[] {
    return this.logs.filter((l) => l.date === date);
  }

  // Build a month grid (leading/trailing days of the surrounding months) for the
  // current month, marking days that have at least one checkin.
  rebuildCalendar(): void {
    const now = new Date();
    const year = now.getFullYear();
    const month = now.getMonth(); // 0-based
    const first = new Date(year, month, 1);
    const startWeekday = first.getDay(); // 0=Sun
    const daysInMonth = new Date(year, month + 1, 0).getDate();

    const checkedDates = new Set<string>();
    for (const l of this.logs) checkedDates.add(l.date);

    const out: CalendarDay[] = [];
    // Leading days from previous month.
    const prevDays = new Date(year, month, 0).getDate();
    for (let i = startWeekday - 1; i >= 0; i--) {
      const d = prevDays - i;
      const ds = CheckinController.formatDate(year, month - 1, d);
      out.push({ date: ds, dayNumber: d, inMonth: false, hasCheckin: checkedDates.has(ds) });
    }
    for (let d = 1; d <= daysInMonth; d++) {
      const ds = CheckinController.formatDate(year, month, d);
      out.push({ date: ds, dayNumber: d, inMonth: true, hasCheckin: checkedDates.has(ds) });
    }
    // Trailing days to fill the last week.
    while (out.length % 7 !== 0) {
      const d = out.length - startWeekday - daysInMonth + 1;
      const ds = CheckinController.formatDate(year, month + 1, d);
      out.push({ date: ds, dayNumber: d, inMonth: false, hasCheckin: checkedDates.has(ds) });
    }
    this.calendarDays = out;
  }

  private static formatDate(year: number, month: number, day: number): string {
    const d = new Date(year, month, day);
    const y = d.getFullYear();
    const m = (d.getMonth() + 1).toString().padStart(2, '0');
    const dd = d.getDate().toString().padStart(2, '0');
    return `${y}-${m}-${dd}`;
  }
}

