import { CheckinLog, ShareCardData, todayDateString } from '../model/Types';
import { DecisionStore } from './DecisionStore';

export class ShareCardController {
  cardData: ShareCardData | null = null;

  // Derive card from today's decision (open-share-result flow).
  fromDecision(): ShareCardData | null {
    const dish = DecisionStore.get();
    if (!dish) {
      this.cardData = null;
      return null;
    }
    this.cardData = {
      title: '今天吃这个',
      dishName: dish.name,
      date: todayDateString(),
      tagline: ShareCardController.taglineForDecision(dish.name),
      source: 'decision',
    };
    return this.cardData;
  }

  // Derive card from a checkin log (open-share-checkin flow).
  fromCheckin(log: CheckinLog): ShareCardData {
    this.cardData = {
      title: '今日打卡',
      dishName: log.dishName,
      date: log.date,
      tagline: ShareCardController.taglineForCheckin(log.mealType),
      source: 'checkin',
    };
    return this.cardData;
  }

  // V1: trigger card "save". Returns whether cardData is present.
  // Actual gallery write is wired during visual integration with system capabilities.
  save(): boolean {
    return this.cardData !== null;
  }

