// ProfileController.ets
//
// Profile surface actions: clear-all-data and export-checkin-data.
// clearAll wipes persisted user data + shared decision. export returns a
// human-readable text summary (V1: no filesystem dependency).

import { StorageService } from '../services/StorageService';
import { CheckinLog } from '../model/Types';
import { DecisionStore } from './DecisionStore';

export class ProfileController {
  async clearAll(): Promise<void> {
    await StorageService.clearAll();
    DecisionStore.clear();
  }

  // Returns a text summary of checkins for export/share.
  async exportCheckinSummary(): Promise<string> {
    const logs: CheckinLog[] = await StorageService.getCheckins();
    if (logs.length === 0) return '暂无打卡记录';
    const lines: string[] = [`我的饮食打卡（共 ${logs.length} 条）`, ''];
    const sorted = logs.slice().sort((a, b) => a.date.localeCompare(b.date));
    for (const l of sorted) {
      const note = l.note.length > 0 ? ` · ${l.note}` : '';
      lines.push(`${l.date} ${ProfileController.mealLabel(l.mealType)} ${l.dishName}${note}`);
    }
    return lines.join('\n');
  }

  private static mealLabel(mealType: string): string {
    if (mealType === 'breakfast') return '早餐';
    if (mealType === 'lunch') return '午餐';
    if (mealType === 'dinner') return '晚餐';
    return '加餐';
  }
}

