// DecisionStore.ets
//
// Shared "today's decision" state, exposed through AppStorage so the wheel,
// mood use-dish, and share-card surfaces stay in sync.
// Headless logic: get/set/clear the current decision dish.

import { Dish } from '../model/Types';

const KEY_DECISION = 'currentDecision';
const KEY_DECISION_AT = 'currentDecisionAtMs';

export class DecisionStore {
  static set(dish: Dish): void {
    AppStorage.setOrCreate<Dish>(KEY_DECISION, dish);
    AppStorage.setOrCreate<number>(KEY_DECISION_AT, Date.now());
  }

  static get(): Dish | null {
    const v = AppStorage.get<Dish>(KEY_DECISION);
    return v ?? null;
  }

  static clear(): void {
    AppStorage.setOrCreate<Dish>(KEY_DECISION, null as object as Dish);
  }

  static hasDecision(): boolean {
    return DecisionStore.get() !== null;
  }
}

