// RecommendService.ets
//
// Stateless local recommendation / filter / spin logic over the built-in DishLibrary.
// All behavior lives on-device; no network calls.

import { DishLibrary } from '../data/DishLibrary';
import {
  Dish,
  Ingredient,
  normalizeIngredientName,
  RecommendResult,
  SpinResult,
  Taste,
} from '../model/Types';
export class RecommendService {
  // --- Wheel ---

  static spin(segmentCount: number = 8): SpinResult {
    const count = Math.min(segmentCount, DishLibrary.all().length);
    const segments = DishLibrary.pickSegments(count);
    const targetIndex = Math.floor(Math.random() * segments.length);
    // At least 5 full rotations + a partial to land on the target.
    const rotations = 5 + Math.floor(Math.random() * 3);
    const durationMs = 3200;
    return { segments, targetIndex, rotations, durationMs };
  }

  // --- Ingredient-based recommendation ---

  static recommendByIngredients(ingredients: Ingredient[]): RecommendResult[] {
    const userNames: string[] = [];
    for (const ing of ingredients) {
      const n = normalizeIngredientName(ing.name);
      if (n.length > 0) userNames.push(n);
    }
    if (userNames.length === 0) return [];

    const results: RecommendResult[] = [];
    for (const dish of DishLibrary.all()) {
      const dishIngs = dish.ingredients.map((s) => normalizeIngredientName(s));
      let matched = 0;
      for (const u of userNames) {
        for (const d of dishIngs) {
          if (d === u || d.indexOf(u) >= 0 || u.indexOf(d) >= 0) {
            matched++;
            break;
          }
        }
      }
      if (matched === 0) continue;

      const matchKind = RecommendService.classifyMatch(matched, dishIngs.length, userNames.length);
      const score = RecommendService.scoreMatch(matchKind, matched, dishIngs.length);
      results.push({ dish, matchCount: matched, matchScore: score, matchKind });
    }

    // Sort: full > partial > mainOnly, then matchCount desc, then cookMinutes asc.
    results.sort((a, b) => {
      const ka = RecommendService.kindRank(a.matchKind);
      const kb = RecommendService.kindRank(b.matchKind);
      if (ka !== kb) return kb - ka;
      if (b.matchCount !== a.matchCount) return b.matchCount - a.matchCount;
      return a.dish.cookMinutes - b.dish.cookMinutes;
    });
    return results;
  }

  private static classifyMatch(matched: number, dishIngCount: number, userCount: number): string {
    if (matched >= dishIngCount) return 'full';
    if (matched >= Math.ceil(dishIngCount / 2)) return 'partial';
    return 'mainOnly';
  }

  private static scoreMatch(kind: string, matched: number, dishIngCount: number): number {
    const base = kind === 'full' ? 80 : kind === 'partial' ? 55 : 30;
    const ratio = dishIngCount > 0 ? matched / dishIngCount : 0;
    return Math.min(100, Math.round(base + ratio * 20));
  }

  private static kindRank(kind: string): number {
    if (kind === 'full') return 3;
    if (kind === 'partial') return 2;
    return 1;
  }

  // --- Mood / time / taste filter ---

  static filterDishes(mood: string, mealTime: string, taste: string): Dish[] {
    const out: Dish[] = [];
    for (const dish of DishLibrary.all()) {
      const moodOk = mood.length === 0 || dish.moods.indexOf(mood) >= 0;
      const timeOk = mealTime.length === 0 || dish.mealTimes.indexOf(mealTime) >= 0;
      const tasteOk = taste.length === 0 || taste === Taste.RANDOM || dish.tastes.indexOf(taste) >= 0;
      if (moodOk && timeOk && tasteOk) out.push(dish);
    }
    return out;
  }

  // Fallback when no filter dimension is chosen: surface a small varied set.
  static defaultSuggestions(): Dish[] {
    return DishLibrary.pickSegments(6);
  }
}

