// StorageService.ets
//
// Local persistence layer built on @ohos.data.preferences.
// Stores user ingredients, checkin logs, and decision history as JSON strings.
// No network, no secrets. Real local behavior.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import { CheckinLog, DecisionRecord, Ingredient } from '../model/Types';

const STORE_NAME = 'eat_what_store';
const KEY_INGREDIENTS = 'ingredients';
const KEY_CHECKINS = 'checkins';
const KEY_DECISIONS = 'decisions';

export class StorageService {
  private static context: common.Context | null = null;
  private static pref: preferences.Preferences | null = null;

  // Must be called once on app launch (e.g. from EntryAbility) with a valid context.
  static init(ctx: common.Context): void {
    StorageService.context = ctx;
  }

  private static async ensurePref(): Promise<preferences.Preferences> {
    if (StorageService.pref) {
      return StorageService.pref;
    }
    if (!StorageService.context) {
      throw new Error('StorageService not initialized: call init(context) first');
    }
    StorageService.pref = await preferences.getPreferences(StorageService.context, STORE_NAME);
    return StorageService.pref;
  }

  // --- Ingredients ---

  static async getIngredients(): Promise<Ingredient[]> {
    const raw = await StorageService.readString(KEY_INGREDIENTS, '');
    return StorageService.parseIngredients(raw);
  }

  static async saveIngredients(list: Ingredient[]): Promise<void> {
    await StorageService.writeString(KEY_INGREDIENTS, JSON.stringify(list));
  }

  // --- Checkins ---

  static async getCheckins(): Promise<CheckinLog[]> {
    const raw = await StorageService.readString(KEY_CHECKINS, '');
    return StorageService.parseCheckins(raw);
  }

  static async saveCheckins(list: CheckinLog[]): Promise<void> {
    await StorageService.writeString(KEY_CHECKINS, JSON.stringify(list));
  }

  // --- Decision history ---

  static async getDecisions(): Promise<DecisionRecord[]> {
    const raw = await StorageService.readString(KEY_DECISIONS, '');
    return StorageService.parseDecisions(raw);
  }

  static async appendDecision(record: DecisionRecord): Promise<void> {
    const list = await StorageService.getDecisions();
    list.push(record);
    // Keep the last 50 decisions to bound storage growth.
    const trimmed = list.length > 50 ? list.slice(list.length - 50) : list;
    await StorageService.writeString(KEY_DECISIONS, JSON.stringify(trimmed));
  }

  // --- Reset ---

  static async clearAll(): Promise<void> {
    const pref = await StorageService.ensurePref();
    await pref.delete(KEY_INGREDIENTS);
    await pref.delete(KEY_CHECKINS);
    await pref.delete(KEY_DECISIONS);
    await pref.flush();
  }

  // --- internals ---

  private static async readString(key: string, def: string): Promise<string> {
    const pref = await StorageService.ensurePref();
    const val = await pref.get(key, def);
    return typeof val === 'string' ? val : def;
  }

  private static async writeString(key: string, value: string): Promise<void> {
    const pref = await StorageService.ensurePref();
    await pref.put(key, value);
    await pref.flush();
  }

  private static parseIngredients(raw: string): Ingredient[] {
    if (!raw) return [];
    try {
      const arr: object[] = JSON.parse(raw) as object[];
      const out: Ingredient[] = [];
      for (const o of arr) {
        const item = o as Ingredient;
        if (item && typeof item.id === 'string' && typeof item.name === 'string') {
          out.push({ id: item.id, name: item.name });
        }
      }
      return out;
    } catch (e) {
      return [];
    }
  }

  private static parseCheckins(raw: string): CheckinLog[] {
    if (!raw) return [];
    try {
      const arr: object[] = JSON.parse(raw) as object[];
      const out: CheckinLog[] = [];
      for (const o of arr) {
        const item = o as CheckinLog;
        if (item && typeof item.id === 'string' && typeof item.date === 'string'
          && typeof item.mealType === 'string' && typeof item.dishName === 'string') {
          out.push({
            id: item.id,
            date: item.date,
            mealType: item.mealType,
            dishName: item.dishName,
            note: typeof item.note === 'string' ? item.note : '',
            createdAtMs: typeof item.createdAtMs === 'number' ? item.createdAtMs : 0,
